import React, { useState, useEffect } from 'react'
import axios from 'axios'
import './App.css'
import { Table, Tag, Input, Button, Space, BackTop, Tooltip } from 'antd'
import Highlighter from 'react-highlight-words'
import { SearchOutlined } from '@ant-design/icons'

function swapArr(arr, index1, index2) {
  arr[index1] = arr.splice(index2, 1, arr[index1])[0]
  return arr
}

// 检索
let searchState = {
  searchText: '',
  searchedColumn: ''
}

function handleSearch(selectedKeys, confirm, dataIndex) {
  confirm()
  searchState = {
    searchText: selectedKeys[0],
    searchedColumn: dataIndex,
  }
}

function handleReset(clearFilters) {
  clearFilters()
  searchState = { searchText: '' }
}

let searchInput = null

function getColumnSearchProps(dataIndex) {
  return {
    filterDropdown: ({ setSelectedKeys, selectedKeys, confirm, clearFilters }) => (
      <div style={{ padding: 8 }}>
        <Input
          ref={node => {
            searchInput = node
          }}
          placeholder={`Search ${dataIndex}`}
          value={selectedKeys[0]}
          onChange={e => setSelectedKeys(e.target.value ? [e.target.value] : [])}
          onPressEnter={() => handleSearch(selectedKeys, confirm, dataIndex)}
          style={{ width: 188, marginBottom: 8, display: 'block' }}
        />
        <Space>
          <Button
            type="primary"
            onClick={() => handleSearch(selectedKeys, confirm, dataIndex)}
            icon={<SearchOutlined />}
            size="small"
            style={{ width: 90 }}
          >
            Search
          </Button>
          <Button onClick={() => handleReset(clearFilters)} size="small" style={{ width: 90 }}>
            Reset
          </Button>
        </Space>
      </div>
    ),
    filterIcon: filtered => <SearchOutlined style={{ color: filtered ? '#1890ff' : undefined }} />,
    onFilter: (value, record) =>
      record[dataIndex].toString().toLowerCase().includes(value.toLowerCase()),
    onFilterDropdownVisibleChange: visible => {
      if (visible) {
        setTimeout(() => searchInput.select())
      }
    },
    render: text => searchState.searchedColumn === dataIndex ? (
      <Highlighter
        highlightStyle={{ backgroundColor: '#ffc069', padding: 0 }}
        searchWords={[searchState.searchText]}
        autoEscape
        textToHighlight={text.toString()}
      />
    ) : (
        text
      )
  }
}

function App() {
  const state = {
    loading: false,
    size: 'small'
  }
  const [dataSource, setDataSource] = useState([])
  const [expandable, setExpandable] = useState({})
  const [dataPrintScreen, setDataPrintScreen] = useState({})
  const [nameList, setNameList] = useState('')
  const [filters, setFilters] = useState([])
  const [attrDetail] = useState({
    "劲足3级": "坐骑的饱食度大于86%时，移动速度额外提升8%",
    "劲足5级": "坐骑的饱食度大于86%时，移动速度额外提升12%",
    "劲足6级": "坐骑的饱食度大于86%时，移动速度额外提升14%",
    "劲足7级": "坐骑的饱食度大于86%时，移动速度额外提升16%",
    "劲足8级": "坐骑的饱食度大于86%时，移动速度额外提升18%",
    "匹马5级": "在非双人同骑的时候，速度额外提升9%",
    "匹马6级": "在非双人同骑的时候，速度额外提升10%",
    "匹马7级": "在非双人同骑的时候，速度额外提升12%",
  })

  useEffect(() => {
    const fetchData = async () => {
      // 列表数据
      // const mounts = await axios.get('https://wz950116.bj.bcebos.com/jx3-pvx%2F%E5%9D%90%E9%AA%91%2Fpublic%2Fmounts.json')
      const mounts = await axios.get('http://wz950116.com/assets/data/mounts/mounts.json')
      setDataSource(mounts.data)

      // 详情数据
      // const dataDescription = await axios.get('https://wz950116.bj.bcebos.com/jx3-pvx%2F%E5%9D%90%E9%AA%91%2Fpublic%2Fdescription.json')
      const dataDescription = await axios.get('http://wz950116.com/assets/data/mounts/description.json')
      const expandable = {
        expandedRowRender: record => <p>{dataDescription.data[record.name] || dataDescription.data[record.name + record.suffix]}</p>,
        rowExpandable: record => !!(dataDescription.data[record.name] || dataDescription.data[record.name + record.suffix])
      }
      setExpandable(expandable)

      // 截图
      // const dataPrintScreen = await axios.get('https://wz950116.bj.bcebos.com/jx3-pvx%2F%E5%9D%90%E9%AA%91%2Fpublic%2Fprintscreen.json')
      const dataPrintScreen = await axios.get('http://wz950116.com/assets/data/mounts/printscreen.json')
      setDataPrintScreen(dataPrintScreen.data)
    }
    fetchData()
  }, [])

  useEffect(() => {
    // 排序
    const nameList = [], filters = []
    dataSource.forEach(v => {
      if (!nameList.includes(v.name)) {
        nameList.push(v.name)
        filters.push({
          text: v.name,
          value: v.name,
          speed: v.speed.replace('%', '')
        })
      }
    })
    filters.sort((a, b) => {
      return a.speed - b.speed
    })
    setNameList(nameList.join())
    setFilters(filters)
  }, [dataSource])

  const columns = [
    {
      title: '名称',
      dataIndex: 'name',
      filters,
      onFilter: (value, record) => record.name.indexOf(value) === 0
    },
    {
      title: '后缀',
      dataIndex: 'suffix',
      align: 'center'
    },
    {
      title: '移动速度',
      dataIndex: 'speed',
      align: 'center',
      sorter: {
        compare: (a, b) => a.speed.replace('%', '') - b.speed.replace('%', '')
      }
    },
    {
      title: '综合速度',
      dataIndex: 'total_speed',
      align: 'center',
      sorter: {
        compare: (a, b) => a.total_speed.replace('%', '') - b.total_speed.replace('%', '')
      }
    },
    {
      title: '属性',
      dataIndex: 'tags',
      render: (text, row, index) => {
        const tags = [row.attrs_1, row.attrs_2, row.attrs_3, row.attrs_4]
        if (row.attrs_2.includes('劲足') || row.attrs_2.includes('匹马')) {
          const index = tags.indexOf(row.attrs_2)
          swapArr(tags, index, 0)
        }
        if (row.attrs_3.includes('劲足') || row.attrs_3.includes('匹马')) {
          const index = tags.indexOf(row.attrs_3)
          swapArr(tags, index, 0)
        }
        if (row.attrs_4.includes('劲足') || row.attrs_4.includes('匹马')) {
          const index = tags.indexOf(row.attrs_4)
          swapArr(tags, index, 0)
        }
        if (row.doubleRide === '1') tags.unshift('双骑')
        return (
          <span>
            {tags.map(tag => {
              if (!tag) return null
              let color = tag === '双骑' ? 'volcano' : tag.includes('劲足') || tag.includes('匹马') ? 'geekblue' : 'green'
              return (
                <React.Fragment key={tag}>
                  {
                    attrDetail[tag] ? (
                      <Tooltip placement="top" title={attrDetail[tag]} key={tag}>
                        <Tag color={color} key={tag}>
                          {tag.toUpperCase()}
                        </Tag>
                      </Tooltip>
                    ) : (
                        <Tag color={color} key={tag}>
                          {tag.toUpperCase()}
                        </Tag>
                      )
                  }
                </React.Fragment>
              )
            })}
          </span>
        )
      }
    },
    {
      title: '品质等级',
      dataIndex: 'grade',
      align: 'center'
    },
    {
      title: '成马UID',
      dataIndex: 'uid',
      ...getColumnSearchProps('uid')
    },
    {
      title: '马驹UID / 出处',
      dataIndex: 'child_uid',
      ...getColumnSearchProps('child_uid')
    },
    {
      title: '截图',
      dataIndex: 'printscreen',
      align: 'center',
      render: (text, row, index) => {
        return (
          dataPrintScreen[row.name + '·' + row.suffix] ?
            <a href={dataPrintScreen[row.name + '·' + row.suffix]} target='_blank' rel='noreferrer noopener'>
              <SearchOutlined style={{ fontSize: '14px', color: '#08c', cursor: 'pointer' }} />
            </a> : dataPrintScreen[row.name] ?
              <a href={dataPrintScreen[row.name]} target='_blank' rel='noreferrer noopener'>
                <SearchOutlined style={{ fontSize: '14px', color: '#08c', cursor: 'pointer' }} />
              </a> : ''
        )
      }
    }
  ]

  return (
    <React.Fragment>
      {false ? nameList : ''}
      <Table {...state} expandable={expandable} columns={columns} dataSource={dataSource} pagination={false} />
      <BackTop>
        <div className="ant-back-top-content"><div className="ant-back-top-icon"></div></div>
      </BackTop>
    </React.Fragment>
  )
}

export default App
